import collections
rows=[l.rstrip('\n').split('\t') for l in open('data/ceb.trn')]
lem_prefixes=['mahimo nga','mang','mag','mo','ma','mi','na','pa']
vowels=set('aeiou')
def strip_lem(lem):
    for p in lem_prefixes:
        if lem.startswith(p) and len(lem)>len(p): return p, lem[len(p):]
    return '', lem
def build(train):
    tab=collections.defaultdict(collections.Counter); gtab=collections.defaultdict(collections.Counter)
    for lem,inf,f in train:
        lp,stem=strip_lem(lem)
        if inf.endswith(stem):
            op=inf[:len(inf)-len(stem)].rstrip('-')
            tab[(lp,f)][op]+=1; gtab[f][op]+=1
    return {k:c.most_common(1)[0][0] for k,c in tab.items()},{k:c.most_common(1)[0][0] for k,c in gtab.items()}
def predict(lem,f,maj,gmaj):
