import collections
rows=[l.rstrip('\n').split('\t') for l in open('data/ceb.trn')]
lem_prefixes=['mahimo nga','mang','mag','mo','ma','mi','na','pa']
vowels=set('aeiou')
FEATS=['V;FUT','V;NFIN','V;PST','V;PRS','V;PROG;PRS','V;PRF;PST']
def strip_lem(lem):
    for p in lem_prefixes:
        if lem.startswith(p) and len(lem)>len(p): return p, lem[len(p):]
    return '', lem
DYN={'V;FUT':'mo','V;NFIN':'mo','V;PST':'ni','V;PRS':'nag','V;PROG;PRS':'ning','V;PRF;PST':'na'}
def build(train):
    tab=collections.defaultdict(collections.Counter); g=collections.defaultdict(collections.Counter)
    bylem=collections.defaultdict(dict)
    for lem,inf,f in train: bylem[lem][f]=inf
    for lem,d in bylem.items():
        lp,stem=strip_lem(lem)
        for f,inf in d.items():
            if inf.endswith(stem):
                op=inf[:len(inf)-len(stem)].rstrip('-'); tab[(lp,f)][op]+=1; g[f][op]+=1
    return bylem,{k:c.most_common(1)[0][0] for k,c in tab.items()},{k:c.most_common(1)[0][0] for k,c in g.items()}
def known_prefixes(L,bylem):
    lp,stem=strip_lem(L); out=set()
    for f,inf in bylem.get(L,{}).items():
        if inf.endswith(stem): out.add(inf[:len(inf)-len(stem)].rstrip('-'))
    return out
def predict(L,f,bylem,maj,gmaj):
    lp,stem=strip_lem(L)
    kp=known_prefixes(L,bylem)
    dynamic = (lp=='mo') or (lp=='ma' and (kp & {'ni','nag','ning'}))
